// // This module decodes a 4-bit input to produce an output that is HIGH (0) when the input is 3, 6, or 9, and LOW (1) otherwise.
module top_module(x, out);input	[3:0]	x;
	output			out;
	reg			out;
	always @(*) begin
		case (x)
			3,6,9:	out = 1;	
			default:	out = 0;	
		endcase
	end	
endmodule
